  ('dietitian-moex-04230', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據衛生福利部之建議，飲食應以清淡為原則，每日鈉攝取量以不超過多少毫克為原則？', '["2,400", "3,000", "4,200", "6,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "cfe2ad5d83fc", "answer_pdf_sha1": "e5ac6dfb7c17", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04231', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何者不是原住民的傳統食物？', '["阿拜（A Bai）", "娘惹糕（Nyonya Kuih）", "奇拿富（Cinavu）", "石板烤山豬肉"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "cfe2ad5d83fc", "answer_pdf_sha1": "e5ac6dfb7c17", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04232', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關職場健康促進，下列敘述何者錯誤？', '["WHO建立的「職場周全健康促進推動模式」中強調應包含「生理工作環境」、「社會心理工作環境」、「個 人健康資源」及「企業社區參與」四大層面", "衛生福利部國民健康署自民國96年起開始辦理全國「健康職場認證」，其績優健康職場的獎項中包含「營 養健康獎」，目的是鼓勵職場致力於改變員工飲食行為", "職場健康促進計畫之核心價值為「企業／組織的領導承諾」及「員工共同參與」", "健康職場認證的實施對象為國內合法設立之公、民營事業單位或機關（構）皆可納入，無資格要求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "cfe2ad5d83fc", "answer_pdf_sha1": "e5ac6dfb7c17", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04233', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '與衛生福利部長期照顧十年計畫1.0（長照1.0）相較，長照2.0擴大納入那些服務對象？', '["65歲以上失能老人", "55歲以上原住民", "未滿50歲失能身心障礙者", "50歲以上身心障礙者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "cfe2ad5d83fc", "answer_pdf_sha1": "e5ac6dfb7c17", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
